    if (Array.isArray(coinData.networkList) && coinData.networkList.length > 0) {
        for (const chain of coinData.networkList) {

            // Создаем объект с правильными именами полей для PostgreSQL
            const record = {
                coin_name: coinName,
                chain_type: chain.network,
                withdraw_fee: chain.withdrawFee,
                deposit_min: chain.minDeposit,
                withdraw_min: chain.minWithdraw,
                confirmation: chain.minConfirm, // Теперь это число, а не строка
                chain: chain.netWork,
                exchange: 'MEXC',

                // ***********************************************
                // НОВОЕ ПОЛЕ: Извлекаем адрес контракта из поля 'contract'
                contract_address: chain.contract || null,
                // ***********************************************

                last_updated: new Date().toISOString()
            };

            // Добавляем созданную запись в массив
            transformedData.push({ json: record });
        }
    }
