    const currentJson = currentItem.json || currentItem;

    // Объединяем текущий объект (currentJson) с аккумулятором
    // Если ключи совпадают, будет использоваться значение из текущего (последнего) объекта.
    return {
        ...accumulator,
        ...currentJson
    };
}, {}); // Начинаем с пустого объекта

// Возвращаем результат в формате, удобном для n8n (один элемент с объединенным JSON)
return [{
    json: mergedObject
}];

// Этот код предназначен для использования в узле, следующем за узлом получения серверного времени.
// Предполагается, что items[0].json содержит поле "data" с UNIX-таймстемпом.

