const htxTimeData = items[0].json;
const rawServerTimeMs = htxTimeData.data; // Получаем 1759672349830

// Преобразуем UNIX-таймстемп (в миллисекундах) в формат ISO 8601 UTC
// HTX требует формат YYYY-MM-DDTHH:mm:ss (без миллисекунд и 'Z')
const serverTimeISO = new Date(Number(rawServerTimeMs)).toISOString().slice(0, 19);

// <--- ВАШ ПУБЛИЧНЫЙ КЛЮЧ ---
const AccessKeyId = 'h6n2d4f5gh-a1e3d346-026874f5-3789d'; 
// Если ключ приходит из настроек, используйте:
// const AccessKeyId = settingsItem.apiKey; 
