// --- ПАРАМЕТРЫ ЗАПРОСА ---
const method = 'GET';
const host = 'api.huobi.pro'; 
// Конечная точка для получения информации о всех валютах и их цепочках
const path = '/v2/reference/currencies'; 

// 2. Обязательные query-параметры для ЛЮБОГО подписанного запроса HTX
const queryParams = {
    'AccessKeyId': AccessKeyId,
    'SignatureMethod': 'HmacSHA256',
    'SignatureVersion': '2',
    'Timestamp': serverTimeISO // Используем преобразованное время в ISO 8601
};

// 3. Сортировка параметров и формирование строки запроса (без подписи!)
// HTX требует, чтобы параметры были отсортированы по алфавиту для подписи.
const sortedKeys = Object.keys(queryParams).sort();
const queryString = sortedKeys.map(key => 
    // Важно: кодирование URL-компонентов
    `${encodeURIComponent(key)}=${encodeURIComponent(queryParams[key])}`
).join('&');

// 4. Формирование строки для подписи (String to Sign)
// Эту строку нужно передать в Cloudflare Worker для HMAC-SHA256.
const signPayload = 
    `${method}\n` +
    `${host}\n` +
    `${path}\n` +
    `${queryString}`;

// 5. Подготовка данных для следующего узла (Cloudflare Worker)
const outputItem = {
    json: {
        // Строка для подписи (для внешнего ресурса)
        signPayload: signPayload, 

        // Финальный URL, куда будет добавлена подпись (Signature)
        baseUrlWithParams: `https://${host}${path}?${queryString}`, 

        // Дополнительные параметры для удобства
        host: host,
        path: path,
        method: method,
        AccessKeyId: AccessKeyId,

        // Передаем точное время (для отладки)
        serverTimeISO: serverTimeISO,

        // Заголовки (обычно не нужны для HTX, но для полноты)
        headers: {
            'Content-Type': 'application/json'
        }
    }
};

// Поскольку это запрос для получения настроек, на выходе должен быть один элемент.
return [outputItem];

