const finalItems = [];

for (const item of items) {
    const json = item.json;

    // Получаем многострочную строку
    const signPayload = json.signPayload;

    // Экранируем символы перевода строки (\n -> \\n)
    // В JavaScript-коде нужно использовать ДВА слэша, чтобы получить ОДИН в строке.
    // Например: 'a\nb'.replace(/\n/g, '\\n') даст 'a\\nb'
    const safeSignPayload = signPayload.replace(/\n/g, '\\n');

    // Формируем тело запроса для Cloudflare Worker
    json.requestBody = {
        signPayload: safeSignPayload,
        baseUrlWithParams: json.baseUrlWithParams
    };

    finalItems.push({ json });
